[asy]
pair A,B,C,D,M,P,Q;

A = (0,0);
B=(1,0);
C=(1,1);
D=(0,1);
P = (0.8,0);
Q = (0,0.6);
M = (P+Q)/2;
draw(A--M);
draw(P--Q--D--C--B--A--Q);
label("$A$",A, SW);
